import {
  Combobox as ComboboxPrimitive,
  type CollectionItem,
  type ComboboxRootComponent as ArkComboboxRootComponent,
  type ComboboxRootProps as ArkComboboxRootProps,
  type ComboboxRootProviderComponent as ArkComboboxRootProviderComponent,
  type ComboboxRootProviderProps as ArkComboboxRootProviderProps,
  useCombobox,
  useComboboxContext,
  useComboboxItemContext,
} from '@ark-ui/react/combobox';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef, ForwardedRef, ReactNode } from 'react';
import { forwardRef } from 'react';
import { CheckIcon, ChevronUpDownIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import {
  OverlayPortal,
  OverlayPortalProvider,
  type OverlayPortalProps,
} from '@/lib/moduix/overlayPortal';
import { CloseButton } from '../close-button';
import styles from './Combobox.module.css';

type ComboboxRootProps<T extends CollectionItem> = ArkComboboxRootProps<T> & OverlayPortalProps;
type ComboboxRootProviderProps<T extends CollectionItem> = ArkComboboxRootProviderProps<T> &
  OverlayPortalProps;

const ComboboxRoot = forwardRef(function ComboboxRoot<T extends CollectionItem>(
  { className, portalled, portalRef, ...props }: ComboboxRootProps<T>,
  ref: ForwardedRef<HTMLDivElement>,
) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <ComboboxPrimitive.Root
        ref={ref}
        data-slot="combobox-root"
        className={clsx(styles.root, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortalProvider>
  );
}) as ArkComboboxRootComponent<OverlayPortalProps>;

const ComboboxRootProvider = forwardRef(function ComboboxRootProvider<T extends CollectionItem>(
  { className, portalled, portalRef, ...props }: ComboboxRootProviderProps<T>,
  ref: ForwardedRef<HTMLDivElement>,
) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <ComboboxPrimitive.RootProvider
        ref={ref}
        data-slot="combobox-root-provider"
        className={clsx(styles.root, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortalProvider>
  );
}) as ArkComboboxRootProviderComponent<OverlayPortalProps>;

const ComboboxLabel = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Label>,
  ComponentProps<typeof ComboboxPrimitive.Label>
>(function ComboboxLabel({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Label
      ref={ref}
      data-slot="combobox-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxControl = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Control>,
  ComponentProps<typeof ComboboxPrimitive.Control>
>(function ComboboxControl({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Control
      ref={ref}
      data-slot="combobox-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxInput = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Input>,
  ComponentProps<typeof ComboboxPrimitive.Input>
>(function ComboboxInput({ asChild, className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Input
      ref={ref}
      data-slot="combobox-input"
      asChild={asChild}
      className={clsx(!asChild && styles.input, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxClearTrigger = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.ClearTrigger>,
  ComponentProps<typeof ComboboxPrimitive.ClearTrigger>
>(function ComboboxClearTrigger(
  {
    asChild,
    className,
    children,
    'aria-label': ariaLabel,
    'aria-labelledby': ariaLabelledBy,
    ...props
  },
  ref,
) {
  const triggerClassName = clsx(styles.clearTrigger, normalizeClassName(className));

  if (asChild) {
    return (
      <ComboboxPrimitive.ClearTrigger
        ref={ref}
        asChild
        data-slot="combobox-clear-trigger"
        className={triggerClassName}
        aria-label={ariaLabel}
        aria-labelledby={ariaLabelledBy}
        {...props}
      >
        {children}
      </ComboboxPrimitive.ClearTrigger>
    );
  }

  return (
    <ComboboxPrimitive.ClearTrigger
      ref={ref}
      asChild
      data-slot="combobox-clear-trigger"
      className={triggerClassName}
      {...props}
    >
      <CloseButton.Root
        aria-label={ariaLabel ?? (ariaLabelledBy == null ? 'Clear selection' : undefined)}
        aria-labelledby={ariaLabelledBy}
      >
        {children}
      </CloseButton.Root>
    </ComboboxPrimitive.ClearTrigger>
  );
});

const ComboboxTrigger = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Trigger>,
  ComponentProps<typeof ComboboxPrimitive.Trigger>
>(function ComboboxTrigger({ className, children, ...props }, ref) {
  return (
    <ComboboxPrimitive.Trigger
      ref={ref}
      data-slot="combobox-trigger"
      className={clsx(styles.trigger, normalizeClassName(className))}
      {...props}
    >
      {children ?? <ChevronUpDownIcon />}
    </ComboboxPrimitive.Trigger>
  );
});

const ComboboxPositioner = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Positioner>,
  ComponentProps<typeof ComboboxPrimitive.Positioner>
>(function ComboboxPositioner({ className, ...props }, ref) {
  return (
    <OverlayPortal>
      <ComboboxPrimitive.Positioner
        ref={ref}
        data-slot="combobox-positioner"
        className={clsx(styles.positioner, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortal>
  );
});

const ComboboxContent = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Content>,
  ComponentProps<typeof ComboboxPrimitive.Content>
>(function ComboboxContent({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Content
      ref={ref}
      data-slot="combobox-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxEmpty = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Empty>,
  ComponentProps<typeof ComboboxPrimitive.Empty>
>(function ComboboxEmpty({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Empty
      ref={ref}
      data-slot="combobox-empty"
      className={clsx(styles.empty, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxStatus = forwardRef<HTMLDivElement, ComponentProps<'div'>>(function ComboboxStatus(
  { className, ...props },
  ref,
) {
  return (
    <div
      ref={ref}
      data-slot="combobox-status"
      className={clsx(styles.status, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxList = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.List>,
  ComponentProps<typeof ComboboxPrimitive.List>
>(function ComboboxList({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.List
      ref={ref}
      data-slot="combobox-list"
      className={clsx(styles.list, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxItemGroup = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.ItemGroup>,
  ComponentProps<typeof ComboboxPrimitive.ItemGroup>
>(function ComboboxItemGroup({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.ItemGroup
      ref={ref}
      data-slot="combobox-item-group"
      className={clsx(styles.itemGroup, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxItemGroupLabel = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.ItemGroupLabel>,
  ComponentProps<typeof ComboboxPrimitive.ItemGroupLabel>
>(function ComboboxItemGroupLabel({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.ItemGroupLabel
      ref={ref}
      data-slot="combobox-item-group-label"
      className={clsx(styles.itemGroupLabel, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxItem = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Item>,
  ComponentProps<typeof ComboboxPrimitive.Item>
>(function ComboboxItem({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Item
      ref={ref}
      data-slot="combobox-item"
      className={clsx(styles.item, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxItemText = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.ItemText>,
  ComponentProps<typeof ComboboxPrimitive.ItemText>
>(function ComboboxItemText({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.ItemText
      ref={ref}
      data-slot="combobox-item-text"
      className={clsx(styles.itemText, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxItemIndicator = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.ItemIndicator>,
  ComponentProps<typeof ComboboxPrimitive.ItemIndicator>
>(function ComboboxItemIndicator({ className, children, ...props }, ref) {
  return (
    <ComboboxPrimitive.ItemIndicator
      ref={ref}
      data-slot="combobox-item-indicator"
      className={clsx(styles.itemIndicator, normalizeClassName(className))}
      {...props}
    >
      {children ?? <CheckIcon />}
    </ComboboxPrimitive.ItemIndicator>
  );
});

type ComboboxOptionProps = Omit<
  ComponentProps<typeof ComboboxPrimitive.Item>,
  'asChild' | 'children'
> & {
  children: ReactNode;
  indicator?: ReactNode | false;
};

const ComboboxOption = forwardRef<ComponentRef<typeof ComboboxPrimitive.Item>, ComboboxOptionProps>(
  function ComboboxOption({ children, indicator, ...props }, ref) {
    return (
      <ComboboxItem ref={ref} {...props}>
        <ComboboxItemText>{children}</ComboboxItemText>
        {indicator !== false ? <ComboboxItemIndicator>{indicator}</ComboboxItemIndicator> : null}
      </ComboboxItem>
    );
  },
);

const Combobox = Object.assign(ComboboxRoot, {
  Root: ComboboxRoot,
  RootProvider: ComboboxRootProvider,
  Label: ComboboxLabel,
  Control: ComboboxControl,
  Input: ComboboxInput,
  ClearTrigger: ComboboxClearTrigger,
  Trigger: ComboboxTrigger,
  Positioner: ComboboxPositioner,
  Content: ComboboxContent,
  Empty: ComboboxEmpty,
  Status: ComboboxStatus,
  List: ComboboxList,
  ItemGroup: ComboboxItemGroup,
  ItemGroupLabel: ComboboxItemGroupLabel,
  Item: ComboboxItem,
  ItemText: ComboboxItemText,
  ItemIndicator: ComboboxItemIndicator,
  Option: ComboboxOption,
  Context: ComboboxPrimitive.Context,
  ItemContext: ComboboxPrimitive.ItemContext,
});

export { Combobox, useCombobox, useComboboxContext, useComboboxItemContext };

@layer moduix.components {
  @keyframes combobox-content-open {
    from {
      opacity: var(
        --moduix-combobox-content-closed-opacity,
        var(--moduix-popup-motion-starting-opacity, 0)
      );
      translate: var(--moduix-popup-motion-starting-translate-x, 0)
        var(--moduix-popup-motion-starting-translate-y, 0);
      transform: scale(
        var(
          --moduix-combobox-content-closed-scale,
          var(--moduix-popup-motion-starting-scale, var(--moduix-scale-popup))
        )
      );
    }

    to {
      opacity: 1;
      translate: 0 0;
      transform: scale(1);
    }
  }

  @keyframes combobox-content-closed {
    from {
      opacity: 1;
      translate: 0 0;
      transform: scale(1);
    }

    to {
      opacity: var(
        --moduix-combobox-content-closed-opacity,
        var(--moduix-popup-motion-ending-opacity, 0)
      );
      translate: var(--moduix-popup-motion-ending-translate-x, 0)
        var(--moduix-popup-motion-ending-translate-y, 0);
      transform: scale(
        var(
          --moduix-combobox-content-closed-scale,
          var(--moduix-popup-motion-ending-scale, var(--moduix-scale-popup))
        )
      );
    }
  }

  .root {
    box-sizing: border-box;
    display: flex;
    width: var(--moduix-combobox-width, 16rem);
    max-width: var(--moduix-combobox-max-width, 100%);
    min-width: 0;
    flex-direction: column;
    gap: var(--moduix-combobox-root-gap, var(--moduix-spacing-1-5));
    color: var(--moduix-combobox-color, var(--moduix-color-foreground));
  }

  .label {
    display: inline-flex;
    align-items: center;
    color: var(
      --moduix-combobox-label-color,
      var(--moduix-combobox-color, var(--moduix-color-foreground))
    );
    font-size: var(--moduix-combobox-label-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-combobox-label-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-combobox-label-line-height, var(--moduix-line-height-text-sm));
    user-select: none;

    &[data-disabled] {
      opacity: var(--moduix-combobox-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .control {
    position: relative;
    display: flex;
    width: 100%;
    min-width: 0;
    align-items: center;
    border: var(--moduix-combobox-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-combobox-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-combobox-radius, var(--moduix-radius-md));
    background-color: var(--moduix-combobox-bg, var(--moduix-color-background));
    color: var(--moduix-combobox-color, var(--moduix-color-foreground));
    outline: var(
        --moduix-combobox-focus-ring-width,
        var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
      )
      solid transparent;
    outline-offset: calc(
      var(
          --moduix-combobox-focus-ring-width,
          var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
        ) *
        -1
    );
    transition:
      background-color var(--moduix-combobox-transition, var(--moduix-transition-default)),
      border-color var(--moduix-combobox-transition, var(--moduix-transition-default)),
      outline-color var(--moduix-combobox-transition, var(--moduix-transition-default));

    &[data-state='open'] {
      border-color: var(--moduix-combobox-focus-ring-color, var(--moduix-color-ring));
      outline-color: var(--moduix-combobox-focus-ring-color, var(--moduix-color-ring));
    }

    &[data-focus] {
      border-color: var(--moduix-combobox-focus-ring-color, var(--moduix-color-ring));
      outline-color: var(--moduix-combobox-focus-ring-color, var(--moduix-color-ring));
    }

    &[data-invalid] {
      border-color: var(--moduix-combobox-invalid-color, var(--moduix-color-destructive));
      outline-color: var(--moduix-combobox-invalid-color, var(--moduix-color-destructive));
    }

    &[data-disabled] {
      opacity: var(--moduix-combobox-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .input {
    box-sizing: border-box;
    width: 100%;
    min-width: 0;
    height: var(--moduix-combobox-control-height, var(--moduix-size-md));
    margin: 0;
    border: 0;
    border-radius: inherit;
    padding-inline: var(--moduix-combobox-input-padding-x-start, var(--moduix-spacing-3-5))
      var(--moduix-combobox-input-padding-x-end, var(--moduix-spacing-3-5));
    background: transparent;
    color: inherit;
    font: inherit;
    outline: 0;

    &::placeholder {
      color: var(--moduix-combobox-input-placeholder-color, var(--moduix-color-muted-foreground));
    }
  }

  .control:has(.trigger) .input {
    padding-inline-end: var(--moduix-combobox-input-padding-x-end-with-trigger, 2.75rem);
  }

  .control:has(.clearTrigger) .input {
    padding-inline-end: var(--moduix-combobox-input-padding-x-end-with-clear, 4.375rem);
  }

  .trigger {
    position: absolute;
    top: 50%;
    box-sizing: border-box;
    display: inline-flex;
    width: var(--moduix-combobox-action-size, var(--moduix-size-xs));
    height: var(--moduix-combobox-action-size, var(--moduix-size-xs));
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    margin: 0;
    border: 0;
    border-radius: var(--moduix-combobox-action-radius, var(--moduix-radius-sm));
    padding: 0;
    background: var(--moduix-combobox-action-bg, transparent);
    color: var(--moduix-combobox-icon-color, var(--moduix-color-muted-foreground));
    line-height: 0;
    transform: translateY(-50%);
    cursor: pointer;
    transition:
      background-color var(--moduix-combobox-transition, var(--moduix-transition-default)),
      color var(--moduix-combobox-transition, var(--moduix-transition-default)),
      opacity var(--moduix-combobox-transition, var(--moduix-transition-default));

    & > svg {
      display: block;
      width: var(--moduix-combobox-icon-size, var(--moduix-spacing-4));
      height: var(--moduix-combobox-icon-size, var(--moduix-spacing-4));
    }

    &:focus-visible {
      outline: var(
          --moduix-combobox-focus-ring-width,
          var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
        )
        solid var(--moduix-combobox-focus-ring-color, var(--moduix-color-ring));
      outline-offset: var(--moduix-combobox-focus-ring-offset, var(--moduix-border-width-sm));
    }

    &:not(:is([disabled], [data-disabled])) {
      @media (hover: hover) {
        &:hover {
          background-color: var(--moduix-combobox-action-bg-hover, var(--moduix-color-muted));
          color: var(--moduix-combobox-action-color-hover, var(--moduix-color-foreground));
        }
      }
    }

    &:is([disabled], [data-disabled]) {
      cursor: default;
    }
  }

  .trigger {
    inset-inline-end: var(--moduix-combobox-action-offset-right, var(--moduix-spacing-2));
  }

  .clearTrigger {
    --moduix-close-button-size: var(--moduix-combobox-action-size, var(--moduix-size-xs));
    --moduix-close-button-icon-size: var(--moduix-combobox-icon-size, var(--moduix-spacing-4));
    --moduix-close-button-radius: var(--moduix-combobox-action-radius, var(--moduix-radius-sm));
    --moduix-close-button-bg: var(--moduix-combobox-action-bg, transparent);
    --moduix-close-button-bg-hover: var(
      --moduix-combobox-action-bg-hover,
      var(--moduix-color-muted)
    );
    --moduix-close-button-color: var(
      --moduix-combobox-icon-color,
      var(--moduix-color-muted-foreground)
    );
    --moduix-close-button-color-hover: var(
      --moduix-combobox-action-color-hover,
      var(--moduix-color-foreground)
    );
    --moduix-close-button-focus-ring-width: var(
      --moduix-combobox-focus-ring-width,
      var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
    );
    --moduix-close-button-focus-ring-color: var(
      --moduix-combobox-focus-ring-color,
      var(--moduix-color-ring)
    );
    --moduix-close-button-focus-ring-offset: var(
      --moduix-combobox-focus-ring-offset,
      var(--moduix-border-width-sm)
    );
    --moduix-close-button-transition: var(
      --moduix-combobox-transition,
      var(--moduix-transition-default)
    );

    position: absolute;
    top: 50%;
    inset-inline-end: calc(
      var(--moduix-combobox-action-offset-right, var(--moduix-spacing-2)) +
        var(--moduix-combobox-action-size, var(--moduix-size-xs)) +
        var(--moduix-combobox-action-gap, var(--moduix-spacing-0-5))
    );
    transform: translateY(-50%);
  }

  .positioner {
    z-index: var(--z-index);
    outline: 0;
  }

  .content {
    box-sizing: border-box;
    z-index: calc(var(--moduix-z-popup) + var(--layer-index, 0));
    display: flex;
    min-width: var(--reference-width);
    max-width: var(--available-width);
    max-height: min(var(--moduix-combobox-content-max-height, 24rem), var(--available-height));
    flex-direction: column;
    overflow: auto;
    border: var(--moduix-combobox-content-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-combobox-content-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-combobox-radius, var(--moduix-radius-md));
    padding-block: var(
      --moduix-combobox-content-padding-y,
      var(--moduix-popup-list-padding-y, var(--moduix-spacing-1))
    );
    background-color: var(--moduix-combobox-content-bg, var(--moduix-color-popover));
    box-shadow: var(--moduix-combobox-content-shadow, var(--moduix-shadow-lg));
    color: var(--moduix-combobox-content-color, var(--moduix-color-popover-foreground));
    transform-origin: var(--transform-origin);
    outline: 0;
    overscroll-behavior: contain;
    scroll-padding-block: var(--moduix-combobox-content-padding-y, var(--moduix-spacing-1));

    &[data-state='open'] {
      animation: combobox-content-open
        var(
          --moduix-combobox-transition,
          var(--moduix-popup-motion-duration, var(--moduix-duration-normal))
            var(--moduix-popup-motion-easing, var(--moduix-ease-in-out))
        );
    }

    &[data-state='closed'] {
      animation: combobox-content-closed
        var(
          --moduix-combobox-transition,
          var(--moduix-popup-motion-duration, var(--moduix-duration-normal))
            var(--moduix-popup-motion-easing, var(--moduix-ease-in-out))
        );
    }
  }

  .list {
    display: flex;
    min-height: 0;
    flex-direction: column;
    outline: 0;

    &[data-empty] {
      display: none;
    }
  }

  .empty,
  .status {
    padding-block: var(--moduix-combobox-empty-padding-y, var(--moduix-spacing-1));
    padding-inline: var(--moduix-combobox-empty-padding-x, var(--moduix-spacing-4));
    color: var(--moduix-combobox-empty-color, var(--moduix-color-muted-foreground));
    font-size: var(--moduix-combobox-empty-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-combobox-empty-line-height, var(--moduix-line-height-text-sm));
  }

  .itemGroup {
    display: flex;
    flex-direction: column;

    & + & {
      margin-top: var(--moduix-combobox-item-group-gap, var(--moduix-spacing-2));
    }
  }

  .itemGroupLabel {
    position: sticky;
    top: calc(-1 * var(--moduix-combobox-content-padding-y, var(--moduix-spacing-1)));
    z-index: 1;
    padding-block: var(
      --moduix-combobox-item-group-label-padding-y,
      var(--moduix-popup-group-label-padding-y, var(--moduix-spacing-1))
    );
    padding-inline: var(--moduix-combobox-item-group-label-padding-x, var(--moduix-spacing-2-5));
    background-color: var(--moduix-combobox-content-bg, var(--moduix-color-popover));
    color: var(
      --moduix-combobox-item-group-label-color,
      var(--moduix-popup-group-label-color, var(--moduix-color-muted-foreground))
    );
    font-size: var(
      --moduix-combobox-item-group-label-font-size,
      var(--moduix-popup-group-label-font-size, var(--moduix-text-xs))
    );
    font-weight: var(
      --moduix-combobox-item-group-label-font-weight,
      var(--moduix-popup-group-label-font-weight, var(--moduix-weight-regular))
    );
    line-height: var(
      --moduix-combobox-item-group-label-line-height,
      var(--moduix-popup-group-label-line-height, var(--moduix-line-height-text-xs))
    );
  }

  .item {
    box-sizing: border-box;
    position: relative;
    display: flex;
    width: calc(100% - var(--moduix-combobox-item-inset-x, var(--moduix-spacing-2)));
    min-height: var(
      --moduix-combobox-item-min-height,
      var(--moduix-popup-item-min-height, var(--moduix-size-sm))
    );
    align-items: center;
    justify-content: space-between;
    gap: var(--moduix-combobox-item-gap, var(--moduix-spacing-2));
    margin-inline: calc(var(--moduix-combobox-item-inset-x, var(--moduix-spacing-2)) / 2);
    border: var(--moduix-combobox-item-border-width, 0) solid
      var(--moduix-combobox-item-border-color, transparent);
    border-radius: var(--moduix-combobox-item-radius, var(--moduix-radius-sm));
    padding-block: var(
      --moduix-combobox-item-padding-y,
      var(--moduix-popup-item-padding-y, var(--moduix-spacing-1))
    );
    padding-inline: var(
      --moduix-combobox-item-padding-x,
      var(--moduix-popup-item-padding-x-start, var(--moduix-spacing-3))
    );
    background-color: var(--moduix-combobox-item-bg, transparent);
    color: var(
      --moduix-combobox-item-color,
      var(--moduix-combobox-content-color, var(--moduix-color-foreground))
    );
    font: inherit;
    font-size: var(
      --moduix-combobox-item-font-size,
      var(--moduix-popup-item-font-size, var(--moduix-text-sm))
    );
    line-height: var(
      --moduix-combobox-item-line-height,
      var(--moduix-popup-item-line-height, var(--moduix-line-height-text-sm))
    );
    outline: 0;
    cursor: default;
    user-select: none;

    &[data-highlighted] {
      background-color: var(--moduix-combobox-highlight-bg, var(--moduix-color-accent));
      color: var(--moduix-combobox-highlight-color, var(--moduix-color-accent-foreground));
    }

    &[data-state='checked'] {
      color: var(
        --moduix-combobox-item-checked-color,
        var(--moduix-combobox-item-color, var(--moduix-color-foreground))
      );
    }

    &[data-disabled] {
      color: var(--moduix-combobox-item-disabled-color, var(--moduix-color-muted-foreground));
      opacity: var(--moduix-combobox-disabled-opacity, var(--moduix-opacity-disabled));
      pointer-events: none;
    }
  }

  .itemText {
    min-width: 0;
    flex: 1;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .itemIndicator {
    display: inline-flex;
    width: var(--moduix-combobox-item-indicator-size, var(--moduix-spacing-3));
    height: var(--moduix-combobox-item-indicator-size, var(--moduix-spacing-3));
    flex-shrink: 0;
    align-items: center;
    justify-content: center;

    & > svg {
      width: 100%;
      height: 100%;
    }
  }
}
